(function(w){"use strict";const ID="volume-unit";const F={"ml":1e-06,"l":0.001,"cm3":1e-06,"m3":1};function compute(x){const v=Number(x.value);if(!Number.isFinite(v)||!Object.prototype.hasOwnProperty.call(F,x.from)||!Object.prototype.hasOwnProperty.call(F,x.to))return{error:"값과 단위를 올바르게 선택해 주세요."};return{value:v*F[x.from]/F[x.to]}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label>변환할 값</label><input class="hm-calc-input" inputmode="decimal" placeholder="예: 1"></div><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>기준 단위</label><select class="hm-calc-select"><option value="ml">mL</option><option value="l" selected>L</option><option value="cm3">cm³</option><option value="m3">m³</option></select></div><div class="hm-calc-field"><label>변환 단위</label><select class="hm-calc-select"><option value="ml" selected>mL</option><option value="l">L</option><option value="cm3">cm³</option><option value="m3">m³</option></select></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">변환하기</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const input=root.querySelector("input"),sels=root.querySelectorAll("select"),btns=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");btns[0].addEventListener("click",()=>{const r=compute({value:api.parseNumber(input.value),from:sels[0].value,to:sels[1].value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("변환 결과",`${api.formatNumber(r.value,10)} ${sels[1].options[sels[1].selectedIndex].text}`));});btns[1].addEventListener("click",()=>{input.value="";sels[0].value="l";sels[1].value="ml";api.setMessage(msg,"");api.clearResult(res);input.focus();});}
w.HM_CALC.register(ID,{compute,render});})(window);
